queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAttractions ?child ; p:hasTheme_Parks ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Theme_Parks } }
  FILTER(?nf = ?total)
}

